/** Nhãn trạng thái kỳ kế toán — map enum BE → VN */
export function accountingPeriodStatusLabel(status: string | undefined): string {
  switch (status) {
    case 'Open':
      return 'Đang mở';
    case 'Closed':
      return 'Đã đóng';
    case 'Locked':
      return 'Đã khóa';
    default:
      return status ?? '—';
  }
}
