import { hasPermissionCode } from '../utils/erpPermissionCode';

export { hasPermissionCode };

const PREFIX = 'erp-finance:accounting-periods';

export function useAccountingPeriodPermissions() {
  return {
    canRead: hasPermissionCode(`${PREFIX}:read`),
    canClose: hasPermissionCode(`${PREFIX}:close`) || hasPermissionCode(`${PREFIX}:write`),
    canLock: hasPermissionCode(`${PREFIX}:lock`) || hasPermissionCode(`${PREFIX}:write`),
  };
}
